var STRATS = [

  // ===== Group 1 — Single-leg & stock-based (single) =====

  { nm:'Long call', group:'single', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'Pay a premium for uncapped upside if the stock climbs past your strike.',
    beg:'Buying a call is paying a small fee today for the right to buy a stock at a set price (the "strike") until a set date. Think of it as a refundable-only-if-it-works ticket to the upside: if the stock climbs well past your strike you keep all the gains, and if it doesn’t, the most you can lose is what you paid. You’d use it when you’re confident a stock will rise and want big exposure without tying up the full cost of the shares.',
    goal:'Bet direction', view:'Bullish', risk:'Defined (premium)',
    def:{ legs:[{t:'c',k:100,q:1}], net:-4, spot:100, lo:84, hi:124, ks:[100] },
    more:'Long <b>+delta, +gamma, +vega, −theta</b>. Max loss = <span class="k">premium paid</span>, max profit <span class="k">unlimited</span>, BE = <span class="k">strike + premium</span>. Time decay bleeds the position daily, so it needs the move to happen with room to spare before expiry; deep-ITM calls behave like leveraged stock, far-OTM calls are mostly a volatility/lottery bet.',
    grk:[['Δ','+'],['Θ','−'],['V','+']] },

  { nm:'Long put', group:'single', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'Pay a premium to profit as the stock falls — a defined-cost bet against it.',
    beg:'Buying a put is paying a fee for the right to *sell* a stock at a set price until a set date — it pays off when the stock falls. It’s the mirror of a call, and it’s also how you buy insurance on shares you own. Reach for it when you expect a decline, or want a defined-cost bet against a stock without shorting it (which carries unlimited risk).',
    goal:'Bet direction', view:'Bearish', risk:'Defined (premium)',
    def:{ legs:[{t:'p',k:100,q:1}], net:-4, spot:100, lo:76, hi:116, ks:[100] },
    more:'Long <b>−delta, +gamma, +vega, −theta</b>. Max loss = <span class="k">premium</span>, max profit = <span class="k">strike − premium</span> (stock→0), BE = <span class="k">strike − premium</span>. Puts carry positive volatility-skew pricing (downside IV richer), so entries are relatively expensive; as a hedge, size to the shares you’re protecting.',
    grk:[['Δ','−'],['Θ','−'],['V','+']] },

  { nm:'Covered call', group:'single', badge:'warn', badgeTxt:'Owns shares', engine:'yes',
    tag:'Own 100 shares and rent them out — collect premium in a flat market.',
    beg:'You own 100 shares and sell someone the right to buy them from you at a higher price, pocketing a cash premium now. It’s like renting out your stock: you collect rent, and the trade-off is you’ve agreed to sell if the price shoots above the strike. Use it on shares you’re happy to hold or to part with, to earn steady income and lower your effective cost basis in sideways markets.',
    goal:'Earn income', view:'Neutral-bullish', risk:'Owns shares',
    def:{ legs:[{t:'s',k:100,q:1},{t:'c',k:107,q:-1}], net:2.5, spot:100, lo:82, hi:118, ks:[107] },
    more:'Synthetically a <b>short put</b>; net <b>+delta (&lt;100), −vega, +theta</b>. Max profit = <span class="k">(strike − cost basis) + premium</span>, capped above the strike, BE = <span class="k">cost basis − premium</span>; downside otherwise unhedged. Watch early assignment on the short call the night before ex-dividend when it’s ITM and its remaining extrinsic is less than the dividend.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  { nm:'Cash-secured put', group:'single', badge:'warn', badgeTxt:'Cash-secured', engine:'yes',
    tag:'Get paid to place a limit order — buy the stock lower, or keep the cash.',
    beg:'You set aside the cash to buy 100 shares and get paid a premium for promising to buy them at a chosen (lower) price if the stock dips there. It’s getting paid to place a limit order: either the stock stays up and you keep the cash, or it falls and you buy shares you wanted anyway, at a discount. Repeated — sell puts, get assigned, then sell calls on the shares — this is the "wheel."',
    goal:'Acquire stock', view:'Neutral-bullish', risk:'Cash-secured',
    def:{ legs:[{t:'p',k:95,q:-1}], net:3, spot:100, lo:78, hi:114, ks:[95] },
    more:'<b>Short put</b>; net <b>+delta, −vega, +theta</b>. Max profit = <span class="k">premium</span>, max loss = <span class="k">strike − premium</span> (to zero), BE = <span class="k">strike − premium</span>. Identical payoff to a covered call at the same strike; "cash-secured" is the collateral rule that makes an otherwise-blocked naked put defined-risk, and assignment simply converts it to long stock at the strike.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  { nm:'Protective put', group:'single', badge:'warn', badgeTxt:'Owns shares', engine:'yes',
    tag:'Insurance on shares you own — a hard floor under a position you keep.',
    beg:'You own shares and buy a put to guarantee a minimum sale price — insurance on your position. If the stock crashes, your losses stop at the put’s strike; if it keeps rising, you still enjoy the gains, minus the insurance cost. Also called a "married put"; use it to hold a stock through a scary event (earnings, a Fed meeting) without risking a wipeout.',
    goal:'Hedge', view:'Bullish, nervous', risk:'Defined floor',
    def:{ legs:[{t:'s',k:100,q:1},{t:'p',k:95,q:1}], net:-1.5, spot:100, lo:80, hi:120, ks:[95] },
    more:'Long stock + long put = <b>synthetic long call</b>; net <b>+delta, +vega, −theta</b>. Max loss = <span class="k">(stock − put strike) + premium</span>, upside <span class="k">unlimited</span>, BE = <span class="k">stock price + premium</span>. The premium is a recurring drag, so it’s a tactical hedge around known catalysts rather than a permanent overlay; a lower strike is cheaper but covers less.',
    grk:[['Δ','+'],['Θ','−'],['V','+']] },

  { nm:'Protective collar', group:'single', badge:'warn', badgeTxt:'Owns shares', engine:'yes',
    tag:'Bracket a stock between a floor and a ceiling — often for near-zero cost.',
    beg:'You own shares, buy a protective put for a floor, and sell a call above to pay for that put — bracketing your stock between a worst case and a best case. You give up gains beyond the ceiling in exchange for cheap (sometimes free) downside protection. Use it to lock in an unrealized gain you can’t sell yet, or to hold nervously through a period without paying full insurance price.',
    goal:'Hedge', view:'Protect a gain', risk:'Defined band',
    def:{ legs:[{t:'s',k:100,q:1},{t:'p',k:95,q:1},{t:'c',k:108,q:-1}], net:-0.2, spot:100, lo:82, hi:120, ks:[95,108] },
    more:'Long stock + long put − short call; net <b>small +delta, ~flat vega/theta</b>. Max loss = <span class="k">stock − put strike + net premium</span>, max gain = <span class="k">call strike − stock − net premium</span>, BE = <span class="k">stock ± net premium</span>. "Costless" when call premium ≈ put premium; the short call caps upside and can be assigned early around dividends, so set the ceiling above your target exit.',
    grk:[['Δ','+'],['Θ','≈ 0'],['V','≈ 0']] },

  { nm:'Covered put', group:'single', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'Built on a short stock position — losses are uncapped as the underlying rises; the engine will not auto-recommend it.',
    tag:'The bearish twin of the covered call — income against a short, uncapped upside.',
    beg:'The bearish twin of the covered call: you’re short 100 shares (betting they fall) and sell a put to collect premium, agreeing to buy the shares back at the put’s strike. You earn income while your short works, capping your profit at that strike. It only fits when you’re already short and expect a flat-to-down grind — and because a short stock can rise forever, the risk is open-ended.',
    goal:'Earn income', view:'Neutral-bearish', risk:'Undefined up',
    def:{ legs:[{t:'s',k:100,q:-1},{t:'p',k:95,q:-1}], net:3, spot:100, lo:82, hi:122, ks:[95] },
    more:'Short stock + short put; net <b>−delta, −vega, +theta</b>. Max profit = <span class="k">(short price − strike) + premium</span>, loss <span class="k">unbounded above</span>, BE = <span class="k">short price + premium</span>. Undefined upside plus short-stock borrow/recall and dividend-liability costs keep it out of auto-recommendation.',
    grk:[['Δ','−'],['Θ','+'],['V','−']] },

  { nm:'Protective (married) call', group:'single', badge:'warn', badgeTxt:'Shorts shares', engine:'eventual',
    tag:'Insurance for a short seller — cap how much a rally can hurt.',
    beg:'The insurance policy for a short seller: you’re short a stock and buy a call to cap how much a rally can hurt you. If the stock jumps, your loss stops at the call’s strike; if it falls, you keep the short’s profits minus the call’s cost. Use it to hold a short through a squeeze-prone event without unlimited exposure.',
    goal:'Hedge', view:'Bearish, nervous', risk:'Defined ceiling',
    def:{ legs:[{t:'s',k:100,q:-1},{t:'c',k:105,q:1}], net:-1.5, spot:100, lo:80, hi:120, ks:[105] },
    more:'Short stock + long call = <b>synthetic long put</b>; net <b>−delta, +vega, −theta</b>. Max loss = <span class="k">(call strike − short price) + premium</span>, max profit = <span class="k">short price − premium</span> (stock→0), BE = <span class="k">short price − premium</span>. Turns the otherwise-uncapped short into a defined-risk bearish bet; the recurring premium drag makes it tactical.',
    grk:[['Δ','−'],['Θ','−'],['V','+']] },

  { nm:'Covered strangle', group:'single', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'Contains a naked/secured short put whose downside plus the owned shares behaves like a leveraged long — treated as undefined until the put leg is cash-secured.',
    tag:'Stack a covered call and a cash-secured put on a stock you like.',
    beg:'You own 100 shares, sell a call above the price and a put below it — collecting two premiums at once to supercharge the income on a stock you like. If it rises past the call you sell your shares at a profit; if it falls past the put you buy a second lot cheaper. It’s a covered call and a cash-secured put stacked on the same name, best when you’re bullish long-term and expect range-bound chop.',
    goal:'Earn income', view:'Neutral-bullish', risk:'Undefined down',
    def:{ legs:[{t:'s',k:100,q:1},{t:'c',k:108,q:-1},{t:'p',k:92,q:-1}], net:4, spot:100, lo:78, hi:120, ks:[92,108] },
    more:'Long stock + short call + short put; net <b>+delta, −vega, +theta</b>. Max profit = <span class="k">call-side capped gain + both premiums</span>; downside = holding stock <b>plus</b> being assigned more at the put strike; upper BE ≈ call-strike area, lower BE = <span class="k">put strike − total premium</span>. Effectively 200-share exposure below the put strike; the engine gates it until the put is explicitly cash-secured.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  // ===== Group 2 — Vertical spreads (vertical) =====

  { nm:'Bull call (debit) spread', group:'vertical', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'A cheaper, capped long call — profit as the stock rises to a target.',
    beg:'You buy a call and simultaneously sell a higher-strike call to help pay for it — a cheaper, capped version of a plain long call. You give up the unlimited upside in exchange for a lower cost and a lower breakeven. Use it when you’re moderately bullish with a specific price target: you profit as the stock rises toward the higher strike, and both your cost and risk are fixed on day one.',
    goal:'Bet direction', view:'Bullish (moderate)', risk:'Defined',
    def:{ legs:[{t:'c',k:97,q:1},{t:'c',k:103,q:-1}], net:-2.5, spot:100, lo:84, hi:116, ks:[97,103] },
    more:'Long lower call − short higher call; net <b>+delta, small vega/theta</b> (roughly delta-driven). Max loss = <span class="k">debit</span>, max profit = <span class="k">width − debit</span>, BE = <span class="k">lower strike + debit</span>. Max value realized only at expiry above the short strike; the short call caps gains and can be assigned early if it goes deep ITM near a dividend.',
    grk:[['Δ','+'],['Θ','≈ 0'],['V','≈ 0']] },

  { nm:'Bear put (debit) spread', group:'vertical', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'A cheaper, capped long put — profit as the stock falls to a target.',
    beg:'The bearish mirror of the bull call spread: buy a put and sell a lower-strike put to cheapen it, profiting as the stock falls toward the lower strike. It’s a lower-cost, capped way to bet on a decline with your risk fixed up front. Use it when you expect a moderate drop to a target rather than a collapse.',
    goal:'Bet direction', view:'Bearish (moderate)', risk:'Defined',
    def:{ legs:[{t:'p',k:103,q:1},{t:'p',k:97,q:-1}], net:-2.5, spot:100, lo:84, hi:116, ks:[97,103] },
    more:'Long higher put − short lower put; net <b>−delta, small vega/theta</b>. Max loss = <span class="k">debit</span>, max profit = <span class="k">width − debit</span>, BE = <span class="k">higher strike − debit</span>. Full profit needs price below the short strike at expiry; the short put carries pin/early-assignment risk when deep ITM.',
    grk:[['Δ','−'],['Θ','≈ 0'],['V','≈ 0']] },

  { nm:'Bear call (credit) spread', group:'vertical', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'Get paid if the stock stays below a level — defined-risk income.',
    beg:'You sell a call and buy a higher-strike call as protection, collecting a net premium up front — you win if the stock stays below your short strike. It’s a bet that a stock *won’t* rise past a level, with the higher-strike call capping your loss if you’re wrong. Use it to earn income in flat-to-down markets, choosing a short strike above a resistance level you don’t expect to break.',
    goal:'Earn income', view:'Neutral-bearish', risk:'Defined',
    def:{ legs:[{t:'c',k:103,q:-1},{t:'c',k:108,q:1}], net:1.8, spot:100, lo:88, hi:118, ks:[103,108] },
    more:'Short lower call + long higher call; net <b>−delta, −vega, +theta</b>. Max profit = <span class="k">credit</span>, max loss = <span class="k">width − credit</span>, BE = <span class="k">short strike + credit</span>. Time decay works for you; manage before expiry to avoid gamma/assignment risk once the short call goes ITM.',
    grk:[['Δ','−'],['Θ','+'],['V','−']] },

  { nm:'Bull put (credit) spread', group:'vertical', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'Get paid if the stock holds a support level — defined-risk income.',
    beg:'You sell a put and buy a lower-strike put for protection, collecting a premium — you win if the stock stays *above* your short strike. It’s the bullish income cousin of the bear call spread: a defined-risk way to get paid for a stock holding a support level. Use it when you’re neutral-to-bullish and want theta income without owning the shares.',
    goal:'Earn income', view:'Neutral-bullish', risk:'Defined',
    def:{ legs:[{t:'p',k:97,q:-1},{t:'p',k:92,q:1}], net:1.6, spot:100, lo:84, hi:110, ks:[92,97] },
    more:'Short higher put + long lower put; net <b>+delta, −vega, +theta</b>. Max profit = <span class="k">credit</span>, max loss = <span class="k">width − credit</span>, BE = <span class="k">short strike − credit</span>. The lower long put converts an otherwise-naked short put into defined risk; the standard high-probability income structure.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  // ===== Group 3 — Volatility: straddles & strangles (volatility) =====

  { nm:'Long straddle', group:'volatility', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'Buy a call and put at the same strike — win on a big move either way.',
    beg:'You buy a call *and* a put at the same strike and date, betting the stock makes a big move but not caring which way. Whichever direction it runs, one leg pays off more than both cost; you only lose if it sits still. Use it ahead of a known event (earnings, a court ruling, an FDA decision) when you expect fireworks but can’t call the direction.',
    goal:'Bet on a move', view:'Big move (either way)', risk:'Defined (premium)',
    def:{ legs:[{t:'c',k:100,q:1},{t:'p',k:100,q:1}], net:-6, spot:100, lo:80, hi:120, ks:[100] },
    more:'Long ATM call + put; net <b>~0 delta, +gamma, +vega, −theta</b>. Max loss = <span class="k">total premium</span> at the strike, BEs = <span class="k">strike ± total premium</span>, upside <span class="k">unlimited</span>. Expensive in high implied vol; the classic trap is post-event "IV crush" — the stock can move yet the position still loses if realized &lt; priced-in vol.',
    grk:[['Δ','≈ 0'],['Θ','−−'],['V','++']] },

  { nm:'Long strangle', group:'volatility', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'A cheaper straddle from OTM options — needs a bigger move to pay.',
    beg:'Like a straddle but cheaper: you buy an out-of-the-money call and an out-of-the-money put, so both legs cost less. The trade-off is the stock has to move *further* before you profit, because there’s a dead zone between the strikes. Use it when you expect a very large move and want to pay less for the bet than a straddle costs.',
    goal:'Bet on a move', view:'Big move (either way)', risk:'Defined (premium)',
    def:{ legs:[{t:'c',k:105,q:1},{t:'p',k:95,q:1}], net:-4, spot:100, lo:78, hi:122, ks:[95,105] },
    more:'Long OTM call + OTM put; net <b>~0 delta, +gamma, +vega, −theta</b>. Max loss = <span class="k">total premium</span> across the whole inter-strike band, BEs = <span class="k">call strike + premium</span> and <span class="k">put strike − premium</span>. Lower cost than the straddle but needs a bigger move; same IV-crush vulnerability around events.',
    grk:[['Δ','≈ 0'],['Θ','−−'],['V','++']] },

  { nm:'Strap', group:'volatility', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A straddle that leans bullish — twice the payoff on an up-move.',
    beg:'A straddle that leans bullish: you buy two calls and one put at the same strike, so you profit from a big move either way but make *twice* as much if the stock rises. Use it when you expect volatility and think an up-move is the more likely of the two big outcomes.',
    goal:'Bet on a move', view:'Volatile, bullish lean', risk:'Defined (premium)',
    def:{ legs:[{t:'c',k:100,q:2},{t:'p',k:100,q:1}], net:-9, spot:100, lo:80, hi:120, ks:[100] },
    more:'Long 2 calls + 1 put ATM; net <b>+delta, +gamma, +vega, −theta</b>. Max loss = <span class="k">total premium</span> at the strike, upside BE = <span class="k">strike + premium/2</span>, downside BE = <span class="k">strike − premium</span>. A leveraged bullish variant of the straddle; costs more than a plain straddle for the extra call.',
    grk:[['Δ','+'],['Θ','−−'],['V','++']] },

  { nm:'Strip', group:'volatility', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A straddle that leans bearish — twice the payoff on a down-move.',
    beg:'The bearish mirror of the strap: buy two puts and one call at the same strike, profiting from a big move either direction but making twice as much on a fall. Use it when you expect volatility and think the downside is the more likely large outcome.',
    goal:'Bet on a move', view:'Volatile, bearish lean', risk:'Defined (premium)',
    def:{ legs:[{t:'p',k:100,q:2},{t:'c',k:100,q:1}], net:-9, spot:100, lo:80, hi:120, ks:[100] },
    more:'Long 2 puts + 1 call ATM; net <b>−delta, +gamma, +vega, −theta</b>. Max loss = <span class="k">total premium</span> at the strike, downside BE = <span class="k">strike − premium/2</span>, upside BE = <span class="k">strike + premium</span>. A leveraged bearish straddle variant.',
    grk:[['Δ','−'],['Θ','−−'],['V','++']] },

  { nm:'Guts (long guts / ITM strangle)', group:'volatility', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A strangle built from ITM options — small max loss, wide profit band.',
    beg:'A strangle built from in-the-money options instead of out-of-the-money ones — you buy an ITM call and an ITM put. Because both start with real intrinsic value, the position always retains at least the gap between the strikes, so the max loss is small relative to the outlay. It’s a rarely-needed alternative to a normal strangle, sometimes preferred when the ITM options are more liquid or better-priced.',
    goal:'Bet on a move', view:'Big move (either way)', risk:'Defined',
    def:{ legs:[{t:'c',k:95,q:1},{t:'p',k:105,q:1}], net:-13, spot:100, lo:82, hi:122, ks:[95,105] },
    more:'Long ITM call (lower strike) + ITM put (higher strike); net <b>~0 delta, +gamma, +vega, −theta</b>. Combined intrinsic between the strikes is constant = width, so max loss = <span class="k">net debit − width</span>, BEs = <span class="k">lower strike − (debit − width)</span> and <span class="k">upper strike + (debit − width)</span>. Ties up more capital than an OTM strangle for the same exposure; the short-guts credit twin is undefined-risk (Group 8).',
    grk:[['Δ','≈ 0'],['Θ','−'],['V','+']] },

  // ===== Group 4 — Butterflies & condors (condors) =====

  { nm:'Long call butterfly', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'A cheap tent-shaped bet that the stock pins one exact strike.',
    beg:'You buy one call low, sell two calls at a middle strike, and buy one call high — a cheap bet that the stock lands right at that middle strike by expiry. The payoff looks like a tent peaking where you sold, and your entire risk is the small amount you paid. Use it when you have a precise price target and expect the stock to sit quietly near it.',
    goal:'Pin a price', view:'Neutral (pin)', risk:'Defined',
    def:{ legs:[{t:'c',k:93,q:1},{t:'c',k:100,q:-2},{t:'c',k:107,q:1}], net:-1.5, spot:100, lo:84, hi:116, ks:[93,100,107] },
    more:'+1 / −2 / +1 calls, equidistant strikes; net <b>~0 delta at center, −vega, +theta</b>. Max profit = <span class="k">width − debit</span> at the center strike, max loss = <span class="k">debit</span>, BEs = <span class="k">lower + debit</span> and <span class="k">upper − debit</span>. Very cheap, low-probability pin bet with high reward-to-risk; peak value only materializes right at expiry (pin/gamma risk into the close).',
    grk:[['Δ','≈ 0'],['Θ','+'],['V','−']] },

  { nm:'Long put butterfly', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'The put-built tent — same pin-the-price bet, tiny defined risk.',
    beg:'The same tent-shaped neutral bet built from puts instead of calls: buy one put low, sell two at the middle, buy one high, profiting most if the stock pins the center strike. Payoff and risk are the same as the call butterfly — you’d pick whichever type is cheaper or more liquid. Use it to target a specific resting price with tiny, defined risk.',
    goal:'Pin a price', view:'Neutral (pin)', risk:'Defined',
    def:{ legs:[{t:'p',k:93,q:1},{t:'p',k:100,q:-2},{t:'p',k:107,q:1}], net:-1.5, spot:100, lo:84, hi:116, ks:[93,100,107] },
    more:'+1 / −2 / +1 puts; <b>identical greeks and payoff to the call butterfly</b> by put-call parity. Max profit = <span class="k">width − debit</span> at center, max loss = <span class="k">debit</span>, BEs = <span class="k">lower + debit</span> and <span class="k">upper − debit</span>. Choose type by pricing/skew and by which side’s assignment you’d rather avoid.',
    grk:[['Δ','≈ 0'],['Θ','+'],['V','−']] },

  { nm:'Iron butterfly', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'Sell an ATM straddle with protective wings — paid for stillness.',
    beg:'You sell a call and a put at the same middle strike (an ATM straddle) and buy a wider call and put as protective wings, collecting a net premium. You keep the most if the stock finishes right at that center strike, and your loss is capped by the wings if it drifts away. It’s the credit-collecting cousin of the long butterfly — same tent shape, but you’re paid up front and want stillness.',
    goal:'Earn income', view:'Neutral (pin)', risk:'Defined both sides',
    def:{ legs:[{t:'p',k:93,q:1},{t:'p',k:100,q:-1},{t:'c',k:100,q:-1},{t:'c',k:107,q:1}], net:4, spot:100, lo:84, hi:116, ks:[93,100,107] },
    more:'Short ATM straddle + long OTM strangle wings; net <b>~0 delta, −vega, +theta</b>. Max profit = <span class="k">net credit</span> at center, max loss = <span class="k">wing width − credit</span>, BEs = <span class="k">center ± credit</span>. Higher premium but narrower profit zone than an iron condor; both short legs sit ATM, so assignment/pin risk is highest of the condor family.',
    grk:[['Δ','≈ 0'],['Θ','++'],['V','−−']] },

  { nm:'Iron condor', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'Sell an OTM put spread and an OTM call spread — win inside a range.',
    beg:'You sell an out-of-the-money put spread below the price and an out-of-the-money call spread above it, collecting premium from both — a bet the stock stays inside a range. As long as it finishes between your two short strikes you keep the full credit; the bought wings cap the loss on either side if it breaks out. It’s the flagship neutral income trade: wide, high-probability, and fully defined-risk.',
    goal:'Earn income', view:'Neutral (range)', risk:'Defined both sides',
    def:{ legs:[{t:'p',k:88,q:1},{t:'p',k:93,q:-1},{t:'c',k:107,q:-1},{t:'c',k:112,q:1}], net:2.4, spot:100, lo:82, hi:118, ks:[88,93,107,112] },
    more:'Short OTM put spread + short OTM call spread; net <b>~0 delta, −vega, +theta</b>. Max profit = <span class="k">net credit</span> between the shorts, max loss = <span class="k">wider spread width − credit</span>, BEs = <span class="k">short put − credit</span> and <span class="k">short call + credit</span>. Profits from range + time decay + falling IV; the main risk is a trend that pushes one short spread ITM (delta/gamma blows out near expiry).',
    grk:[['Δ','≈ 0'],['Θ','+'],['V','−']] },

  { nm:'Long call condor', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A butterfly with a flat top — full profit across a range of prices.',
    beg:'A butterfly with a flat top: buy a low call, sell two calls at two different middle strikes, buy a high call, so instead of one peak you get a *range* of full profit. It pays off if the stock finishes anywhere between the two inner strikes, giving you a wider target than a butterfly for a bit more cost. It’s the all-calls (debit) version of the iron condor.',
    goal:'Pin a range', view:'Neutral (range)', risk:'Defined',
    def:{ legs:[{t:'c',k:90,q:1},{t:'c',k:97,q:-1},{t:'c',k:103,q:-1},{t:'c',k:110,q:1}], net:-2, spot:100, lo:82, hi:118, ks:[90,97,103,110] },
    more:'+1 / −1 / −1 / +1 calls across four ascending strikes; net <b>~0 delta between inner strikes, −vega, +theta</b>. Max profit = <span class="k">inner-strike distance − debit</span>, max loss = <span class="k">debit</span>, BEs = <span class="k">lowest + debit</span> and <span class="k">highest − debit</span>. Equivalent payoff to an iron condor; a long put condor is the put-built twin with identical shape.',
    grk:[['Δ','≈ 0'],['Θ','+'],['V','−']] },

  { nm:'Long put condor', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'The put-built flat-top condor — a debit range bet.',
    beg:'The put-built version of the long condor: buy a high put, sell two puts at middle strikes, buy a low put, profiting if the stock stays in a range. Same wide-target, defined-risk, tent-with-a-flat-top payoff as the call condor — you’d choose whichever is priced better. Use it for a neutral range bet you want to pay a debit for rather than collect a credit.',
    goal:'Pin a range', view:'Neutral (range)', risk:'Defined',
    def:{ legs:[{t:'p',k:110,q:1},{t:'p',k:103,q:-1},{t:'p',k:97,q:-1},{t:'p',k:90,q:1}], net:-2, spot:100, lo:82, hi:118, ks:[90,97,103,110] },
    more:'+1 / −1 / −1 / +1 puts across four strikes; <b>identical greeks/payoff to the long call condor</b> by parity. Max profit = <span class="k">inner distance − debit</span>, max loss = <span class="k">debit</span>, BEs = <span class="k">highest − debit</span> and <span class="k">lowest + debit</span>. Choose call- vs put-built by liquidity/skew and assignment preference.',
    grk:[['Δ','≈ 0'],['Θ','+'],['V','−']] },

  { nm:'Broken-wing butterfly (skip-strike)', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A skewed butterfly you can open for a credit — no loss on one side.',
    beg:'A butterfly with one wing stretched wider than the other, which skews the trade in your favored direction and often lets you open it for a credit instead of paying. The reward: you can build it so there’s *no loss at all* on one side. Use it when you’re neutral-to-directional and want the pinning payoff of a butterfly without symmetric risk — you take on a bit more risk on the far wing to erase it on the near one.',
    goal:'Earn income', view:'Neutral-directional', risk:'Defined (skewed)',
    def:{ legs:[{t:'c',k:100,q:1},{t:'c',k:105,q:-2},{t:'c',k:115,q:1}], net:0.5, spot:100, lo:88, hi:124, ks:[100,105,115] },
    more:'A butterfly with unequal wing widths (a strike "skipped"); net <b>small directional delta, −vega, +theta</b>. Opened for a credit ≥ 0 there is <b>zero risk on the credit side</b>, with max loss = <span class="k">(wide wing − narrow wing) − credit</span> on the other. Popular as a "no-risk-on-one-side" income structure; the trade-off is a larger tail loss if it runs through the wide wing.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  { nm:'Broken-wing condor', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'An iron condor tilted your way — smaller or zero loss on the favored side.',
    beg:'An iron condor with one side’s wing wider than the other, skewing the range toward the direction you lean and often eliminating the risk on your favored side. You keep the wide, high-probability profit zone but no longer take equal losses on both breakouts. Use it when you want condor income but have a directional bias.',
    goal:'Earn income', view:'Neutral-directional', risk:'Defined (skewed)',
    def:{ legs:[{t:'p',k:88,q:1},{t:'p',k:93,q:-1},{t:'c',k:107,q:-1},{t:'c',k:117,q:1}], net:2, spot:100, lo:82, hi:124, ks:[88,93,107,117] },
    more:'Iron condor with asymmetric spread widths; net <b>directional delta, −vega, +theta</b>. The narrower side carries the smaller (or zero) defined loss, the wider side the larger one. A structural way to express a skew view while retaining time-decay income; sizing the wide wing controls the tail.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  { nm:'Reverse (long) iron condor', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'An iron condor flipped — pay a debit to profit from a breakout.',
    beg:'Flip an iron condor upside down: you *buy* the inner options and *sell* the outer ones, paying a debit to profit from a big move in either direction. Instead of wanting the stock to stay in a range, you want it to break out of one, and your loss is capped if it doesn’t move. Use it as a cheaper, defined-risk alternative to a strangle when you expect a breakout but not an unlimited run.',
    goal:'Bet on a move', view:'Breakout (either way)', risk:'Defined',
    def:{ legs:[{t:'p',k:92,q:-1},{t:'p',k:97,q:1},{t:'c',k:103,q:1},{t:'c',k:108,q:-1}], net:-2, spot:100, lo:82, hi:118, ks:[92,97,103,108] },
    more:'Long inner call+put spreads (buy near-ATM, sell farther OTM); net <b>~0 delta, +vega, −theta</b>. Max profit = <span class="k">spread width − debit</span> (beyond either outer strike), max loss = <span class="k">debit</span> in the center, BEs = <span class="k">center strikes ± debit</span>. Caps profit versus a strangle in exchange for a lower cost; wants realized vol &gt; implied and benefits from rising IV. Some brokers call this a "short iron condor".',
    grk:[['Δ','≈ 0'],['Θ','−'],['V','+']] },

  { nm:'Reverse (long) iron butterfly', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A capped, cheaper straddle — bet on a big move with defined risk.',
    beg:'The upside-down iron butterfly: buy an at-the-money straddle and sell wider wings to cheapen it, paying a debit to bet on a big move either way. It behaves like a capped, lower-cost straddle — you profit if the stock moves past either wing and lose the debit if it pins the center. Use it around events when you want breakout exposure with defined risk and a lower price than a straddle.',
    goal:'Bet on a move', view:'Breakout (either way)', risk:'Defined',
    def:{ legs:[{t:'p',k:93,q:-1},{t:'p',k:100,q:1},{t:'c',k:100,q:1},{t:'c',k:107,q:-1}], net:-4, spot:100, lo:84, hi:116, ks:[93,100,107] },
    more:'Long ATM straddle − short OTM strangle wings; net <b>~0 delta, +vega, −theta</b>. Max profit = <span class="k">wing width − debit</span> beyond either wing, max loss = <span class="k">debit</span> at center, BEs = <span class="k">center ± debit</span>. A cheaper, profit-capped straddle; still exposed to IV crush if the move is smaller than priced.',
    grk:[['Δ','≈ 0'],['Θ','−−'],['V','++']] },

  { nm:'Short call butterfly', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'Collect a credit to bet the stock moves away from the center.',
    beg:'The mirror image of a long butterfly: you sell the wings and buy two middle-strike calls, collecting a credit and profiting if the stock moves *away* from the center in either direction. You lose the most only if it pins the middle. Use it as a defined-risk, credit-collecting way to bet against the stock sitting still.',
    goal:'Bet on a move', view:'Move away (either way)', risk:'Defined',
    def:{ legs:[{t:'c',k:93,q:-1},{t:'c',k:100,q:2},{t:'c',k:107,q:-1}], net:1.5, spot:100, lo:84, hi:116, ks:[93,100,107] },
    more:'−1 / +2 / −1 calls; net <b>~0 delta at center, +vega, −theta</b>. Max profit = <span class="k">credit</span> (on both wings), max loss = <span class="k">width − credit</span> at center, BEs = <span class="k">lower + credit</span> and <span class="k">upper − credit</span>. Low, capped reward for a break-either-way view; the put-built short butterfly is identical by parity.',
    grk:[['Δ','≈ 0'],['Θ','−'],['V','+']] },

  { nm:'Short put butterfly', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'The put-built break-either-way credit butterfly.',
    beg:'The all-puts version of the short butterfly: sell the outer puts, buy two middle puts, collect a credit, and profit if the stock moves away from the center either way. Same inverted-tent payoff as the short call butterfly. Pick whichever type prices better for a defined-risk break-either-way bet.',
    goal:'Bet on a move', view:'Move away (either way)', risk:'Defined',
    def:{ legs:[{t:'p',k:93,q:-1},{t:'p',k:100,q:2},{t:'p',k:107,q:-1}], net:1.5, spot:100, lo:84, hi:116, ks:[93,100,107] },
    more:'−1 / +2 / −1 puts; <b>identical greeks/payoff to the short call butterfly</b>. Max profit = <span class="k">credit</span>, max loss = <span class="k">width − credit</span> at center, BEs = <span class="k">lower + credit</span> and <span class="k">upper − credit</span>. Rarely used versus a reverse iron butterfly, which usually offers a better breakout reward.',
    grk:[['Δ','≈ 0'],['Θ','−'],['V','+']] },

  { nm:'Christmas tree butterfly (unbalanced)', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A skewed, skip-strike butterfly aimed at a directional target.',
    beg:'A directional butterfly built with a skipped strike and uneven leg counts (a common form is buy 1, skip a strike, sell 3, buy 2 calls), giving a tent that’s pushed toward your target price. It costs little and pays off if the stock drifts to a specific higher-or-lower zone. Use it as a low-cost, defined-risk way to target a directional move to a level, cheaper than a vertical spread.',
    goal:'Bet direction', view:'Directional (moderate)', risk:'Defined',
    def:{ legs:[{t:'c',k:95,q:1},{t:'c',k:105,q:-3},{t:'c',k:110,q:2}], net:-1, spot:100, lo:84, hi:120, ks:[95,105,110] },
    more:'A ratioed/skip-strike butterfly (e.g. <b>+1 / 0 / −3 / +2 calls</b>) that nets to zero contracts, so risk stays defined; net <b>directional delta, −vega, +theta</b>. Max loss = <span class="k">net debit</span>, profit peaks in the sold-strike zone. The "unbalanced butterfly" umbrella — leg counts and strike skips are tuned to place the peak at the forecast price.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  { nm:'Unbalanced (ratioed) iron condor', group:'condors', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'An iron condor sized heavier on one side for a directional lean.',
    beg:'An iron condor that isn’t symmetric — you put more contracts or a wider spread on one side to reflect a directional lean or to collect more premium. The range-bound payoff stays, but the risk and reward are deliberately skewed. Use it when you want condor income but expect the stock more likely to drift one way.',
    goal:'Earn income', view:'Neutral-directional', risk:'Defined both sides',
    def:{ legs:[{t:'p',k:88,q:2},{t:'p',k:93,q:-2},{t:'c',k:107,q:-1},{t:'c',k:112,q:1}], net:3.4, spot:100, lo:80, hi:120, ks:[88,93,107,112] },
    more:'Iron condor with unequal call- vs put-side contract counts or widths; net <b>directional delta, −vega, +theta</b>. Both sides remain fully spread so risk is <b>defined but asymmetric</b> (the heavier side carries the larger max loss). A way to fold a directional bias and premium-skew harvest into a neutral income base.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  // ===== Group 5 — Ratio spreads & backspreads (ratio) =====

  { nm:'Call ratio (front) spread', group:'ratio', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'Net short an extra call — losses run unlimited if the stock rallies past the upper strike.',
    tag:'Sell an extra call for a credit — bet on a modest rise, capped.',
    beg:'You buy one call and sell two higher-strike calls, usually collecting a credit — a bet the stock rises *modestly* to the short strike but no further. You make the most if it lands right at that strike, and often there’s no loss at all if it instead falls. The catch: because you sold an extra uncovered call, a strong rally past the upper strike loses money without limit, which is why it’s not auto-recommended.',
    goal:'Earn income', view:'Modestly bullish (capped)', risk:'Undefined up',
    def:{ legs:[{t:'c',k:100,q:1},{t:'c',k:107,q:-2}], net:0.5, spot:100, lo:86, hi:124, ks:[100,107] },
    more:'+1 / −2 calls; net <b>−vega, +theta</b>, delta positive then flipping negative past the short strike. Max profit = <span class="k">width + net credit</span> at the short strike, upside loss <span class="k">unlimited</span> above BE = <span class="k">short strike + width + credit</span>, no downside risk if opened for a credit. The extra naked call is the gate; often managed as a covered/financed structure against stock.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  { nm:'Put ratio (front) spread', group:'ratio', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'Net short an extra put — a large (bounded-by-zero) loss if the stock falls hard past the lower strike.',
    tag:'Sell an extra put for a credit — bet on a modest drop.',
    beg:'The bearish mirror of the call ratio spread: buy one put and sell two lower-strike puts, usually for a credit, betting on a *modest* drop to the short strike. Best case, the stock lands at that strike; often there’s no loss if it instead rises. The risk is a sharp crash below the strikes, where the extra sold put produces a large loss — hence it’s gated.',
    goal:'Earn income', view:'Modestly bearish (capped)', risk:'Undefined down',
    def:{ legs:[{t:'p',k:100,q:1},{t:'p',k:93,q:-2}], net:0.5, spot:100, lo:76, hi:114, ks:[93,100] },
    more:'+1 / −2 puts; net <b>−vega, +theta</b>, delta negative then flipping positive below the short strike. Max profit = <span class="k">width + credit</span> at the short strike, downside loss <span class="k">large (to zero)</span> below BE = <span class="k">short strike − width − credit</span>, no upside risk if opened for a credit. The extra naked put drives the gate.',
    grk:[['Δ','−'],['Θ','+'],['V','−']] },

  { nm:'Call ratio backspread', group:'ratio', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'Net long extra calls — unlimited upside on a strong rally.',
    beg:'You sell one call and buy two higher-strike calls, setting up to profit hugely from a strong rally while keeping a small gain (or breaking even) if the stock instead falls. You’re net long extra calls, so a big up-move pays without limit; the worst case is a modest rise that stalls at the long strike. Use it when you expect an explosive up-move (and ideally rising volatility) and want defined risk with unlimited upside.',
    goal:'Bet on a move', view:'Strongly bullish', risk:'Defined',
    def:{ legs:[{t:'c',k:100,q:-1},{t:'c',k:107,q:2}], net:0.5, spot:100, lo:86, hi:124, ks:[100,107] },
    more:'−1 lower call / +2 higher calls; net <b>+vega, −theta, +delta</b>. Max loss = <span class="k">width − net credit</span> at the long strike, upside <span class="k">unlimited</span>, upper BE = <span class="k">long strike + (width − credit)</span>. Wants realized &gt; implied vol; the danger zone is a slow grind up that expires right at the long strike (the max-loss point).',
    grk:[['Δ','+'],['Θ','−'],['V','+']] },

  { nm:'Put ratio backspread', group:'ratio', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'Net long extra puts — big payoff on a sharp selloff.',
    beg:'The bearish mirror: sell one put and buy two lower-strike puts, positioned to profit big from a sharp decline while keeping a small gain if the stock rises instead. You’re net long extra puts, so a crash pays large; the worst outcome is a mild drop that stalls at the long strike. Use it when you expect a fast selloff and want defined risk with a big downside payoff.',
    goal:'Bet on a move', view:'Strongly bearish', risk:'Defined',
    def:{ legs:[{t:'p',k:100,q:-1},{t:'p',k:93,q:2}], net:0.5, spot:100, lo:76, hi:114, ks:[93,100] },
    more:'−1 higher put / +2 lower puts; net <b>+vega, −theta, −delta</b>. Max loss = <span class="k">width − net credit</span> at the long strike, downside profit <span class="k">large (to zero)</span>, lower BE = <span class="k">long strike − (width − credit)</span>. A common crash-hedge/expression that is often cash-neutral to open; danger is a small down-move stalling at the long strike.',
    grk:[['Δ','−'],['Θ','−'],['V','+']] },

  { nm:'ZEBRA (zero-extrinsic back ratio)', group:'ratio', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'Stock replacement with a floor — 1:1 upside, no theta drag.',
    beg:'A stock-replacement trade: buy two in-the-money calls and sell one at-the-money call so the time-value ("extrinsic") of the legs cancels out, leaving a position that moves almost dollar-for-dollar with the stock but risks only what you paid. You get long-stock-like exposure without paying for time decay and with a hard floor on losses. Use it as a defined-risk substitute for buying shares (a put-based version replaces short stock).',
    goal:'Replace stock', view:'Bullish', risk:'Defined (debit)',
    def:{ legs:[{t:'c',k:90,q:2},{t:'c',k:100,q:-1}], net:-13, spot:100, lo:78, hi:120, ks:[90,100] },
    more:'+2 ITM calls − 1 ATM call, structured so <b>net extrinsic ≈ 0 and net delta ≈ 100</b>; net <b>~flat theta/vega, +delta</b>. Max loss = <span class="k">net debit</span>, upside ≈ <span class="k">1:1 with the stock</span>, BE ≈ entry underlying + small offset. Removes the theta drag of a single long call while capping risk; the put-built ZEBRA replaces a short stock position.',
    grk:[['Δ','+'],['Θ','≈ 0'],['V','≈ 0']] },

  // ===== Group 6 — Time spreads: calendars & diagonals (time) =====

  { nm:'Call calendar spread', group:'time', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'Sell a near call, buy a far one at the same strike — harvest faster decay.',
    beg:'You sell a near-term call and buy a longer-term call at the *same* strike, profiting because the option you sold loses value faster than the one you own. You want the stock to sit near that strike as the front option decays, then you keep the longer-dated one (or roll another sale against it). Use it to earn time-decay income around a target price, with a bonus if implied volatility rises.',
    goal:'Earn income', view:'Neutral (pin)', risk:'Defined',
    def:{ tent:true, k:100, peak:2.4, debit:2.6, w:14, spot:100, lo:84, hi:116, ks:[100] },
    more:'−near call / +far call, same strike; net <b>~0 delta near the strike, +vega (long back month), +theta</b>. Max loss = <span class="k">net debit</span> (on a large move either way), profit peaks at the strike at front expiry, BEs bracket the strike. Long vega means a volatility drop hurts even if the stock is pinned; roll or close the front leg before it goes ITM to avoid assignment.',
    grk:[['Δ','≈ 0'],['Θ','+'],['V','+']] },

  { nm:'Put calendar spread', group:'time', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'The put-built calendar — neutral time-decay income around a strike.',
    beg:'The put-built calendar: sell a near-term put and buy a longer-term put at the same strike, again profiting from the faster decay of the front option while the stock hovers near the strike. Same tent-like payoff as the call calendar; traders often pick the put version when the strike is below the price or when put pricing/skew is favorable. Use it for neutral time-decay income around a target.',
    goal:'Earn income', view:'Neutral (pin)', risk:'Defined',
    def:{ tent:true, k:100, peak:2.4, debit:2.6, w:14, spot:100, lo:84, hi:116, ks:[100] },
    more:'−near put / +far put, same strike; net <b>~0 delta near strike, +vega, +theta</b>. Max loss = <span class="k">net debit</span>, peak profit at the strike at front expiry. Same volatility-drop and front-leg-assignment cautions as the call calendar; skew often makes put calendars slightly richer.',
    grk:[['Δ','≈ 0'],['Θ','+'],['V','+']] },

  { nm:'Call diagonal spread', group:'time', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'A calendar with a bullish tilt — decay income plus a mild up-bet.',
    beg:'A calendar with a directional lean: you sell a near-term call and buy a longer-term call at a *different* (usually lower) strike, combining time-decay income with a mild directional bet. It’s like a calendar and a vertical spread rolled together, so it profits from both the stock drifting your way and the front option decaying. Use it when you’re neutral-to-bullish and want to collect premium while keeping longer-dated upside.',
    goal:'Earn income', view:'Neutral-bullish', risk:'Defined',
    def:{ tent:true, k:102, peak:3, debit:2.4, w:15, skew:0.4, spot:100, lo:84, hi:120, ks:[100,105] },
    more:'−near call / +far call at different strikes; net <b>small +delta, +vega, +theta</b>. Max loss = <span class="k">net debit</span>, profit depends on where price sits versus the short strike at front expiry. Combines horizontal (time) and vertical (strike) edges; can often be rolled into a covered-call-like campaign against the long call.',
    grk:[['Δ','+'],['Θ','+'],['V','+']] },

  { nm:'Put diagonal spread', group:'time', badge:'ok', badgeTxt:'Defined risk', engine:'yes',
    tag:'A calendar with a bearish tilt — decay income plus a mild down-bet.',
    beg:'The bearish-leaning diagonal: sell a near-term put and buy a longer-term put at a different (usually higher) strike, blending time-decay income with a mild downward bet. Like the call diagonal but tilted for a stock you think drifts sideways-to-down. Use it to collect premium while holding longer-dated downside exposure.',
    goal:'Earn income', view:'Neutral-bearish', risk:'Defined',
    def:{ tent:true, k:98, peak:3, debit:2.4, w:15, skew:-0.4, spot:100, lo:80, hi:116, ks:[95,100] },
    more:'−near put / +far put at different strikes; net <b>small −delta, +vega, +theta</b>. Max loss = <span class="k">net debit</span>, profit path depends on price versus the short strike at front expiry. Horizontal + vertical edge with a bearish tilt; manage the front put’s assignment risk as it approaches ITM.',
    grk:[['Δ','−'],['Θ','+'],['V','+']] },

  { nm:'Double calendar', group:'time', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'Two calendars at once — a wider profit zone for the stock to wander.',
    beg:'Two calendar spreads at once — one at a strike below the price and one above — giving you a *wider* profit zone than a single calendar. Instead of needing the stock to pin one exact strike, you profit across the whole band between your two humps. Use it for neutral, decay-and-volatility income when you want more room for the stock to wander.',
    goal:'Earn income', view:'Neutral (wider range)', risk:'Defined',
    def:{ tent:true, k:100, peak:2.2, debit:2.8, w:18, spot:100, lo:80, hi:120, ks:[95,105] },
    more:'A put calendar (lower strike) + a call calendar (higher strike); net <b>~0 delta between the humps, +vega, +theta</b>. Max loss = <span class="k">net debit</span>, broadest profit between the two strikes at front expiry. Strongly long vega — a good structure when front-month IV is elevated relative to the back month and you expect a range plus a vol pop. (Payoff is a two-humped hill; sketched here as a wide tent.)',
    grk:[['Δ','≈ 0'],['Θ','+'],['V','++']] },

  { nm:'Double diagonal', group:'time', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A long-vega condor — range income that also gains on an IV spike.',
    beg:'Two diagonal spreads combined, one on each side of the price — essentially an iron condor whose long options are dated farther out, so it collects range-bound income *and* benefits from rising volatility. You keep the wide "stay in the range" payoff of a condor, but with a positive volatility tilt from the longer-dated wings. Use it for neutral income when you also want protection against (or profit from) an IV spike.',
    goal:'Earn income', view:'Neutral (range)', risk:'Defined',
    def:{ tent:true, k:100, peak:2.4, debit:2.6, w:17, spot:100, lo:80, hi:120, ks:[94,106] },
    more:'Short near-term strangle + long farther-dated wider strangle; net <b>~0 delta, +vega, +theta</b>. Max profit between the short strikes at front expiry, max loss ≈ <span class="k">net debit + wing risk</span> (defined). Unlike a plain iron condor it’s <b>long</b> vega, so an IV rise helps rather than hurts; the farther-dated longs retain value for a follow-on roll. (Sketched as a broad tent.)',
    grk:[['Δ','≈ 0'],['Θ','+'],['V','+']] },

  { nm:'Poor man\'s covered call (LEAPS diagonal)', group:'time', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A LEAPS stand-in for stock — run a covered-call campaign for less capital.',
    beg:'A cheaper stand-in for a covered call: instead of buying 100 shares, you buy one deep in-the-money long-dated call (a LEAPS) to act like the stock, then sell shorter-dated calls against it for income. It mimics owning the stock and renting it out, but ties up far less capital. Use it to run a covered-call income campaign on a pricier stock without paying full share price.',
    goal:'Earn income', view:'Neutral-bullish', risk:'Defined (debit)',
    def:{ tent:true, k:105, peak:3, debit:2.6, w:16, skew:0.5, spot:100, lo:84, hi:122, ks:[100,107] },
    more:'Long deep-ITM LEAPS call (high delta) − short near-term OTM call; net <b>+delta (&lt;100), +vega, +theta</b>. Max risk ≈ <span class="k">net debit paid</span>, upside capped above the short strike. The long call substitutes for stock; keep the short strike above <span class="k">long strike + net debit</span> so a called-away scenario stays profitable, and roll the short monthly. ("Fig leaf" = the same idea.) Mechanically a call diagonal, which is engine-yes; a dedicated preset is pending.',
    grk:[['Δ','+'],['Θ','+'],['V','+']] },

  { nm:'Poor man\'s covered put (LEAPS diagonal)', group:'time', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A LEAPS stand-in for short stock — defined-risk bearish income.',
    beg:'The bearish version of the poor man’s covered call: buy a long-dated in-the-money put to stand in for short stock, then sell shorter-dated puts against it for income. It gives short-like exposure and steady premium at a fraction of the capital and *without* the unlimited risk of shorting shares. Use it to run a bearish income campaign with defined risk.',
    goal:'Earn income', view:'Neutral-bearish', risk:'Defined (debit)',
    def:{ tent:true, k:95, peak:3, debit:2.6, w:16, skew:-0.5, spot:100, lo:78, hi:116, ks:[93,100] },
    more:'Long deep-ITM LEAPS put − short near-term OTM put; net <b>−delta (&lt;100 abs), +vega, +theta</b>. Max risk ≈ <span class="k">net debit</span>, gains capped below the short strike. Defined-risk substitute for a covered put (which is undefined); roll the short put and keep the short strike below <span class="k">long strike − debit</span>.',
    grk:[['Δ','−'],['Θ','+'],['V','+']] },

  // ===== Group 7 — Combination & advanced (combo) =====

  { nm:'Jade lizard', group:'combo', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'Contains a naked short put — downside loss runs to (near) zero unless the put is cash-secured.',
    tag:'Sell a put and a call spread for enough credit that the upside can’t hurt.',
    beg:'You sell an out-of-the-money put and, above the price, sell a call spread — collecting enough total premium that there is literally *no risk if the stock rises*. You win on any flat-to-up move and only lose if the stock falls hard through the put. Use it as a high-probability income trade on a stock you’re mildly bullish on, structured so the upside can never hurt you.',
    goal:'Earn income', view:'Neutral-bullish', risk:'Undefined down',
    def:{ legs:[{t:'p',k:92,q:-1},{t:'c',k:107,q:-1},{t:'c',k:112,q:1}], net:5, spot:100, lo:78, hi:120, ks:[92,107,112] },
    more:'Short OTM put + short OTM call spread, sized so <b>total credit ≥ call-spread width → zero upside risk</b>; net <b>+delta, −vega, +theta</b>. Max profit = <span class="k">total credit</span> (any price above the short put up through the calls), downside loss to <span class="k">(put strike − credit)</span>, BE = <span class="k">put strike − total credit</span>. The naked put is the gate (cash-secure it to define risk); the "big lizard" variant sells an ATM straddle instead of a single put and buys a call to cap the upside.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  { nm:'Reverse jade lizard (twisted sister)', group:'combo', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'Contains a naked short call — uncapped loss if the stock rallies.',
    tag:'Sell a call and a put spread — no risk if the stock falls.',
    beg:'The mirror of the jade lizard: you sell an out-of-the-money call and, below the price, sell a put spread — collecting enough premium that there’s *no risk if the stock falls*. You profit on any flat-to-down move and only lose on a strong rally. Use it as a high-probability income trade with a mild bearish lean and no downside risk.',
    goal:'Earn income', view:'Neutral-bearish', risk:'Undefined up',
    def:{ legs:[{t:'c',k:108,q:-1},{t:'p',k:93,q:-1},{t:'p',k:88,q:1}], net:5, spot:100, lo:80, hi:122, ks:[88,93,108] },
    more:'Short OTM call + short OTM put spread, sized so <b>total credit ≥ put-spread width → zero downside risk</b>; net <b>−delta, −vega, +theta</b>. Max profit = <span class="k">total credit</span> below the short call, upside loss <span class="k">unlimited</span> above BE = <span class="k">call strike + total credit</span>. The naked call is the gate.',
    grk:[['Δ','−'],['Θ','+'],['V','−']] },

  { nm:'Risk reversal', group:'combo', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'The sold leg is naked (short put for the bullish version) — loss is bounded only by the stock reaching zero.',
    tag:'Sell a put to finance a call — a cheap, strongly directional bet.',
    beg:'You sell an out-of-the-money put to finance buying an out-of-the-money call, creating a cheap (sometimes free) strongly bullish position that acts a lot like owning stock with a gap in the middle. The upside is unlimited; the price is that a big drop assigns you the stock at the put strike. Use it for a high-conviction directional bet financed by the premium you collect (a bearish version sells the call to buy the put).',
    goal:'Bet direction', view:'Bullish (conviction)', risk:'Undefined down',
    def:{ legs:[{t:'p',k:92,q:-1},{t:'c',k:108,q:1}], net:0.3, spot:100, lo:78, hi:122, ks:[92,108] },
    more:'Short OTM put + long OTM call (bullish); net <b>strongly +delta, long call-skew vega, ~flat theta</b>. Upside <span class="k">unlimited</span> above the call strike, downside loss to <span class="k">(put strike − net credit)</span>, often opened for ≈ zero cost. The naked short put is the gate; a leveraged directional/skew trade widely used to monetize volatility skew.',
    grk:[['Δ','++'],['Θ','≈ 0'],['V','+']] },

  { nm:'Synthetic long stock', group:'combo', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'Contains a naked short put — replicates leveraged long stock, loss bounded only by the stock hitting zero.',
    tag:'A call plus a short put that moves dollar-for-dollar like stock.',
    beg:'You buy a call and sell a put at the same strike, and the combination behaves *exactly* like owning 100 shares — dollar-for-dollar up and down — but for little or no cash outlay. It’s a way to get full stock exposure using options, often to use less capital or when the options market is cheaper than borrowing. The catch is you carry the same downside as owning the stock (all the way to zero), with the short put as the uncapped leg.',
    goal:'Replace stock', view:'Bullish', risk:'Undefined down',
    def:{ legs:[{t:'c',k:100,q:1},{t:'p',k:100,q:-1}], net:-0.2, spot:100, lo:80, hi:120, ks:[100] },
    more:'Long call + short put, same strike/expiry; net <b>+100 delta, ~0 net vega/theta</b>. P/L ≈ <span class="k">(underlying − strike ± net premium)</span>, BE ≈ <span class="k">strike + net cost</span>. By put-call parity it prices as stock minus the cost of carry; the short put is the gate and carries assignment risk plus the full down-to-zero exposure of long stock.',
    grk:[['Δ','++'],['Θ','≈ 0'],['V','≈ 0']] },

  { nm:'Synthetic short stock', group:'combo', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'Contains a naked short call — replicates short stock, loss uncapped on a rally.',
    tag:'A short call plus a put that behaves like being short shares.',
    beg:'The bearish twin: sell a call and buy a put at the same strike, and the pair behaves just like being short 100 shares — profiting as the stock falls, losing as it rises — usually for little or no cost. It’s a way to get short exposure through options, sometimes when the stock is hard or expensive to borrow. Like a real short, the loss on a rally is unlimited, via the naked call leg.',
    goal:'Replace stock', view:'Bearish', risk:'Undefined up',
    def:{ legs:[{t:'c',k:100,q:-1},{t:'p',k:100,q:1}], net:0.2, spot:100, lo:80, hi:120, ks:[100] },
    more:'Short call + long put, same strike/expiry; net <b>−100 delta, ~0 net vega/theta</b>. P/L ≈ <span class="k">(strike − underlying ± net premium)</span>. The short call is the gate; replicates short-stock economics (including uncapped upside loss) and can dodge borrow costs but takes on assignment risk.',
    grk:[['Δ','−−'],['Θ','≈ 0'],['V','≈ 0']] },

  { nm:'Bull call ladder', group:'combo', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'Net short an extra call at the top strike — uncapped loss on a strong rally.',
    tag:'A bull call spread financed by an extra short call — capped, with a tail.',
    beg:'A bull call spread extended by selling one more, even-higher call to cheapen it — you buy a call, sell a higher call, and sell an even-higher call. It profits if the stock rises into the middle zone, but selling that extra top call means an unusually strong rally turns into an open-ended loss. Use it when you expect a *moderate* rise that stalls, and accept the tail risk if it runs — which is why it’s gated.',
    goal:'Bet direction', view:'Moderately bullish', risk:'Undefined up',
    def:{ legs:[{t:'c',k:97,q:1},{t:'c',k:103,q:-1},{t:'c',k:109,q:-1}], net:0.5, spot:100, lo:86, hi:124, ks:[97,103,109] },
    more:'+1 lower call / −1 middle call / −1 upper call; net <b>−vega, +theta</b>, delta positive then flipping short. Max profit = <span class="k">(middle − lower width) + net credit</span> on the plateau, loss <span class="k">unlimited</span> above upper BE = <span class="k">upper strike + plateau profit</span>. Essentially a bull call spread financed by a naked upper call — the extra short is the gate.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  { nm:'Bear put ladder', group:'combo', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'Net short an extra put at the bottom strike — a large (to-zero) loss on a hard selloff.',
    tag:'A bear put spread financed by an extra short put — capped, with a tail.',
    beg:'The bearish mirror of the bull call ladder: buy a put, sell a lower put, and sell an even-lower put, cheapening the trade but adding an extra sold put at the bottom. It profits from a *moderate* decline into the middle zone; the risk is a crash below the strikes where the extra put produces a large loss. Use it when you expect a measured drop that stalls, accepting the downside tail.',
    goal:'Bet direction', view:'Moderately bearish', risk:'Undefined down',
    def:{ legs:[{t:'p',k:103,q:1},{t:'p',k:97,q:-1},{t:'p',k:91,q:-1}], net:0.5, spot:100, lo:78, hi:114, ks:[91,97,103] },
    more:'+1 higher put / −1 middle put / −1 lower put; net <b>−vega, +theta</b>, delta negative then flipping long. Max profit on the plateau between the two lower strikes, <span class="k">large loss below the lower BE</span> (bounded by zero). The extra naked put is the gate.',
    grk:[['Δ','−'],['Θ','+'],['V','−']] },

  { nm:'Bear call ladder', group:'combo', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A three-strike backspread — a bullish breakout despite the name.',
    beg:'Despite the name it’s a bullish/breakout trade: you sell a lower call and buy two higher calls (a three-strike backspread), so a strong rally pays without limit while a flat-or-down move keeps a small credit. The worst case is a middling rise that stalls between the strikes. Use it when you expect either nothing or a big up-move — often as a "repair" that turns a bearish position bullish.',
    goal:'Bet on a move', view:'Volatile / bullish', risk:'Defined',
    def:{ legs:[{t:'c',k:97,q:-1},{t:'c',k:103,q:1},{t:'c',k:109,q:1}], net:0.5, spot:100, lo:86, hi:126, ks:[97,103,109] },
    more:'−1 lower call / +1 middle call / +1 upper call; net <b>+vega, −theta, +delta</b>. Net long calls so upside <span class="k">unlimited</span>, max loss capped in the middle-strike zone, defined risk overall. A three-strike cousin of the call ratio backspread; wants a large up-move and/or rising IV.',
    grk:[['Δ','+'],['Θ','−'],['V','+']] },

  { nm:'Bull put ladder', group:'combo', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A three-strike put backspread — a bearish crash play despite the name.',
    beg:'The mirror of the bear call ladder, and bearish in effect: sell a higher put and buy two lower puts, so a sharp decline pays big while a flat-or-up move keeps a small credit. The danger zone is a modest drop that stalls between the strikes. Use it when you expect either nothing or a large downside move.',
    goal:'Bet on a move', view:'Volatile / bearish', risk:'Defined',
    def:{ legs:[{t:'p',k:103,q:-1},{t:'p',k:97,q:1},{t:'p',k:91,q:1}], net:0.5, spot:100, lo:78, hi:114, ks:[91,97,103] },
    more:'−1 higher put / +1 middle put / +1 lower put; net <b>+vega, −theta, −delta</b>. Net long puts so a crash pays <span class="k">large (to zero)</span>, max loss capped in the middle-strike zone, defined risk. Three-strike cousin of the put ratio backspread; a common crash-protection expression.',
    grk:[['Δ','−'],['Θ','−'],['V','+']] },

  { nm:'Box spread', group:'combo', badge:'ok', badgeTxt:'Defined risk', engine:'eventual',
    tag:'A fully-hedged four-leg trade whose payoff is locked to the strike width.',
    beg:'A fully-hedged four-leg trade (a bull call spread plus a bear put spread at the same strikes) whose value at expiry is *locked* to the distance between the strikes, no matter what the stock does. Because the outcome is fixed, it isn’t a market bet — it’s used as a synthetic loan (a "short box" borrows cash, a "long box" lends it) or to capture a small pricing discrepancy. Use it for cash management or arbitrage, not directional profit.',
    goal:'Finance / arbitrage', view:'Neutral (rate play)', risk:'Defined (locked)',
    def:{ legs:[{t:'c',k:95,q:1},{t:'c',k:105,q:-1},{t:'p',k:105,q:1},{t:'p',k:95,q:-1}], net:-9.5, spot:100, lo:84, hi:116, ks:[95,105] },
    more:'Bull call spread + bear put spread at identical strikes → <b>guaranteed payoff = strike width</b> at expiry; profit = <span class="k">width − net debit</span> (long) ≈ a fixed interest rate, with <b>delta/vega/theta ≈ 0</b>. On American-style equity options early assignment can break the "risk-free" assumption catastrophically — best done on European cash-settled index options; it "makes money" only through favorable financing or mispricing.',
    grk:[['Δ','≈ 0'],['Θ','≈ 0'],['V','≈ 0']] },

  // ===== Group 8 — Undefined-risk (blocked) (undefined) =====

  { nm:'Naked (uncovered) short call', group:'undefined', badge:'bad', badgeTxt:'Undefined risk', engine:'blocked',
    gate:'No long call or stock to cap the upside — a rally produces theoretically unlimited loss; blocked by default.',
    tag:'Sell a call uncovered — fixed premium, open-ended loss on a rally.',
    beg:'You sell a call without owning the stock or a protective call, collecting premium and betting the stock stays below the strike. You keep the whole premium if it does — but if the stock rallies, your loss grows without any limit, because you must deliver shares at the strike no matter how high the price goes. This is why it’s blocked by default: the reward is fixed and small, the risk is open-ended.',
    goal:'Earn income', view:'Neutral-bearish', risk:'Undefined up',
    def:{ legs:[{t:'c',k:100,q:-1}], net:4, spot:100, lo:84, hi:124, ks:[100] },
    more:'Short call; net <b>−delta, −vega, +theta</b>. Max profit = <span class="k">premium</span>, loss <span class="k">unlimited</span> above BE = <span class="k">strike + premium</span>. Requires margin, faces early assignment (especially ITM pre-dividend), and a gap-up can exceed collateral — the archetype of undefined risk.',
    grk:[['Δ','−'],['Θ','+'],['V','−']] },

  { nm:'Naked short put (unsecured)', group:'undefined', badge:'bad', badgeTxt:'Undefined risk', engine:'blocked',
    gate:'Not cash-secured — a hard selloff produces a large loss down to (strike − premium) with no set-aside collateral; blocked by default.',
    tag:'Sell a put with no set-aside cash — a large loss on a hard drop.',
    beg:'You sell a put without setting aside the cash to buy the shares, collecting premium and betting the stock stays above the strike. It’s identical in shape to a cash-secured put, but *without* the reserved cash, so a sharp drop can produce a loss far larger than your account expected. Securing it with cash converts it to the defined-risk Cash-secured put; unsecured, it’s blocked.',
    goal:'Earn income', view:'Neutral-bullish', risk:'Undefined down',
    def:{ legs:[{t:'p',k:100,q:-1}], net:4, spot:100, lo:76, hi:116, ks:[100] },
    more:'Short put; net <b>+delta, −vega, +theta</b>. Max profit = <span class="k">premium</span>, max loss = <span class="k">strike − premium</span> (to zero), BE = <span class="k">strike − premium</span>. Mechanically the same payoff as a covered call; the gate is <b>collateral, not shape</b> — the engine only recommends the cash-secured form.',
    grk:[['Δ','+'],['Θ','+'],['V','−']] },

  { nm:'Short straddle', group:'undefined', badge:'bad', badgeTxt:'Undefined risk', engine:'blocked',
    gate:'Naked on both sides — the short call gives unlimited upside loss, the short put large downside loss; blocked by default.',
    tag:'Sell a call and a put — the purest bet on stillness, uncapped both ways.',
    beg:'You sell a call *and* a put at the same strike, collecting two premiums and betting the stock barely moves. It’s the purest bet on stillness and pays the highest premium of the neutral trades — but a big move in *either* direction produces heavy, and on the upside unlimited, losses. Blocked by default because the reward is capped at the credit while the risk is open-ended on both sides.',
    goal:'Earn income', view:'Neutral (stillness)', risk:'Undefined both sides',
    def:{ legs:[{t:'c',k:100,q:-1},{t:'p',k:100,q:-1}], net:7, spot:100, lo:80, hi:122, ks:[100] },
    more:'Short ATM call + put; net <b>~0 delta, −vega, +theta, −gamma</b>. Max profit = <span class="k">total credit</span> at the strike, BEs = <span class="k">strike ± credit</span>, loss <span class="k">unbounded above and large below</span>. Peak short gamma means losses accelerate as the stock moves; the defined-risk cousin is the Iron butterfly.',
    grk:[['Δ','≈ 0'],['Θ','++'],['V','−−']] },

  { nm:'Short strangle', group:'undefined', badge:'bad', badgeTxt:'Undefined risk', engine:'blocked',
    gate:'Naked on both sides — unlimited upside loss (short call) and large downside loss (short put); blocked by default.',
    tag:'Sell an OTM call and put — wide safe zone, uncapped tails.',
    beg:'You sell an out-of-the-money call and an out-of-the-money put, collecting premium and betting the stock stays inside a range wider than the short straddle’s. It has a bigger safe zone than the straddle but still exposes you to open-ended losses if the stock breaks out hard. Blocked by default; the defined-risk version that buys protective wings is the Iron condor.',
    goal:'Earn income', view:'Neutral (range)', risk:'Undefined both sides',
    def:{ legs:[{t:'c',k:108,q:-1},{t:'p',k:92,q:-1}], net:4, spot:100, lo:78, hi:122, ks:[92,108] },
    more:'Short OTM call + OTM put; net <b>~0 delta, −vega, +theta, −gamma</b>. Max profit = <span class="k">total credit</span> between the shorts, BEs = <span class="k">call strike + credit</span> and <span class="k">put strike − credit</span>, tails <span class="k">unbounded/large</span>. Wider safety than a short straddle for less premium; same uncapped tail risk.',
    grk:[['Δ','≈ 0'],['Θ','++'],['V','−−']] },

  { nm:'Short guts (ITM short strangle)', group:'undefined', badge:'bad', badgeTxt:'Undefined risk', engine:'eventual',
    gate:'Naked ITM call and put — unlimited upside loss, large downside loss; gated like the other naked shorts (riskRank-99).',
    tag:'The ITM short strangle — big credit, big intrinsic owed, same open-ended risk.',
    beg:'The in-the-money version of a short strangle: you sell an ITM call and an ITM put, taking in a large premium but owing the intrinsic value between the strikes at expiry. It behaves like a short strangle with more credit up front and correspondingly more that must be paid back, and it carries the same open-ended breakout risk. Listed for completeness — like the other naked shorts it’s gated and not auto-recommended.',
    goal:'Earn income', view:'Neutral', risk:'Undefined both sides',
    def:{ legs:[{t:'c',k:95,q:-1},{t:'p',k:105,q:-1}], net:13, spot:100, lo:82, hi:122, ks:[95,105] },
    more:'Short ITM call (lower strike) + ITM put (higher strike); net <b>~0 delta, −vega, +theta, −gamma</b>. Keeps <span class="k">credit − width</span> at best (between the strikes), BEs = <span class="k">lower strike − (credit − width)</span> and <span class="k">upper strike + (credit − width)</span>, tails <span class="k">unbounded/large</span>. Economically equivalent to a short OTM strangle by parity but with heavier assignment exposure on both ITM legs; treated with the same riskRank-99 gate as the naked shorts.',
    grk:[['Δ','≈ 0'],['Θ','+'],['V','−']] }

];
